T1 = np.array([2022+n for n in range(3,14)])
N_R = np.array(reg.predict(poly.fit_transform(T1.reshape(-1,1))))*np.array(reg1.predict(poly1.fit_transform(T1.reshape(-1,1))))*365
print(N_R)
plt.figure()
plt.plot(T1,N_R,'o')
plt.semilogy()
